public static boolean isBalanced(int[] arr) {
int sum1 = 0;
int sum2 = 0;
int half = arr.length / 2;

for (int i = 0; i < half; i++) {
sum1 += arr[i];
}

for (int i = half + 1; i < arr.length; i++) {
sum2 += arr[i];
}

if (sum1 == sum2) {
return true;
}
return false;
}

public class Team {
public String teamName;
public int numMembers;
public boolean needsComputers;

public Team(String teamName, int numMembers, boolean needsComputers) {
this.teamName = teamName;
this.numMembers = numMembers;
this.needsComputers = needsComputers;
}

public String getTeamName() {
return teamName;
}
}

public class Hackathon {
private Team[] teams;
private int maxTeams;
private int currentTeams;

public Hackathon(int maxTeams) {
this.maxTeams = maxTeams;
this.teams = new Team[maxTeams];
this.currentTeams = 0;
}

public boolean addTeam(Team t) {
this.teams[currentTeams] = t;
currentTeams++;
return true;
}

public int countComputersNeeded() {
int total = 0;
for (int i = 0; i < teams.length; i++) {
if (teams[i].needsComputers) {
total += teams[i].numMembers;
}
}
return total;
}
}

